sql:
SELECT course_id, SUM(enrollment_count) AS Total_Students
FROM course_enrollment
GROUP BY course_id;

SELECT COUNT(student_id) AS student_count
FROM student_enrollment
WHERE course_id = 1;

SELECT unit_head_id, COUNT(unit_id) AS 'Number of Units Led'
FROM academic_units
GROUP BY unit_head_id;

SELECT unit_name 
FROM academic_units 
WHERE department = 'Business';

SELECT unit_name 
FROM academic_units 
WHERE unit_id = 0;

SELECT AVG(enrollment_count) AS average_enrollment_count
FROM enrollment_data
WHERE enrollment_count > 200;

SELECT COUNT(*) AS instructor_count 
FROM course_instructors 
WHERE course_id = 1;

external_knowledge:
- "a tide of students" refers to a significant influx of students;
- "swelling their ranks past the ripple of 150" implies that the departments have an average enrollment exceeding 150 students;
- "aggregate and average waves of enrollments" refers to the total enrollment count and the average enrollment count;
- "target currents" symbolizes the target enrollment count.

sql:
SELECT c.course_name, d.department
FROM courses c
INNER JOIN academic_units d ON c.unit_id = d.unit_id;

SELECT unit_name, department, unit_head_id
FROM academic_units
WHERE unit_id > 5 AND department = 'Computer Science';

SELECT unit_id, SUM(enrollment_count) AS total_enrollment
FROM enrollment_data
GROUP BY unit_id;

external_knowledge:
- Departments refer to academic units;
- Terms refer to enrollment terms;
- Matching unique identifiers imply a relationship between academic units and terms.

sql:
SELECT courses.course_name, courses.credits, academic_units.unit_name
FROM courses
INNER JOIN academic_units ON courses.unit_id = academic_units.unit_id;

SELECT SUM(enrollment_count) AS total_enrollment
FROM enrollment_data
WHERE unit_id = 1;

SELECT student_id, course_id 
FROM student_enrollment 
WHERE enrollment_status = 'Enrolled';
